import { getSessionTokenFromRequest, hashSessionToken } from '../../../lib/session'

interface Env {
  DB: D1Database
}

interface FunctionContext {
  request: Request
  env: Env
  params: {
    id?: string | string[]
  }
}

interface AuthenticatedSessionRow {
  session_id: number
  session_expires_at: string
  session_revoked_at: string | null
  session_session_version: number
  user_status: string
  user_session_version: number
  role_name: string
  role_is_active: number
}

interface RoleRow {
  id: number
  name: string
  description: string | null
  is_active: number
  created_at: string
  updated_at: string
}

interface RoleUpdateRequest {
  name?: unknown
  description?: unknown
  isActive?: unknown
}

const ROLE_NAME_PATTERN = /^[A-Z][A-Z0-9_]{1,49}$/

function json(payload: unknown, status: number, headers?: HeadersInit): Response {
  return Response.json(payload, { status, headers })
}

function authenticationRequired(): Response {
  return json({ success: false, error: 'Authentication required' }, 401)
}

function mapRole(role: RoleRow) {
  return {
    id: role.id,
    name: role.name,
    description: role.description ?? '',
    status: role.is_active === 1 ? 'ACTIVE' : 'INACTIVE',
    createdAt: role.created_at,
    updatedAt: role.updated_at,
  }
}

async function requireSuperadmin(context: FunctionContext): Promise<Response | null> {
  const sessionToken = getSessionTokenFromRequest(context.request)
  if (!sessionToken) return authenticationRequired()

  const tokenHash = await hashSessionToken(sessionToken)
  const session = await context.env.DB.prepare(
    `SELECT
      s.id AS session_id,
      s.expires_at AS session_expires_at,
      s.revoked_at AS session_revoked_at,
      s.session_version AS session_session_version,
      u.status AS user_status,
      u.session_version AS user_session_version,
      r.name AS role_name,
      r.is_active AS role_is_active
    FROM sessions s
    INNER JOIN users u ON u.id = s.user_id
    INNER JOIN roles r ON r.id = u.role_id
    WHERE s.token_hash = ?
    LIMIT 1`,
  ).bind(tokenHash).first<AuthenticatedSessionRow>()

  if (!session) return authenticationRequired()

  const expiresAt = Date.parse(session.session_expires_at)
  if (
    session.session_revoked_at !== null
    || !Number.isFinite(expiresAt)
    || expiresAt <= Date.now()
    || session.session_session_version !== session.user_session_version
  ) {
    return authenticationRequired()
  }

  if (session.user_status !== 'ACTIVE') {
    return json({ success: false, error: 'User account is inactive' }, 403)
  }

  if (session.role_is_active !== 1) {
    return json({ success: false, error: 'User role is inactive' }, 403)
  }

  if (session.role_name !== 'SUPERADMIN') {
    return json({ success: false, error: 'SUPERADMIN access required' }, 403)
  }

  await context.env.DB.prepare(
    'UPDATE sessions SET last_used_at = CURRENT_TIMESTAMP WHERE id = ?',
  ).bind(session.session_id).run()

  return null
}

export async function onRequest(context: FunctionContext): Promise<Response> {
  if (context.request.method !== 'PATCH') {
    return json({ success: false, error: 'Method not allowed' }, 405, { Allow: 'PATCH' })
  }

  try {
    const authError = await requireSuperadmin(context)
    if (authError) return authError

    const idParam = Array.isArray(context.params.id) ? context.params.id[0] : context.params.id
    const roleId = Number(idParam)

    if (!Number.isInteger(roleId) || roleId <= 0) {
      return json({ success: false, error: 'Role id is invalid' }, 400)
    }

    let body: RoleUpdateRequest
    try {
      const parsedBody: unknown = await context.request.json()
      body = parsedBody && typeof parsedBody === 'object' && !Array.isArray(parsedBody)
        ? parsedBody as RoleUpdateRequest
        : {}
    } catch {
      return json({ success: false, error: 'Request body must be valid JSON' }, 400)
    }

    const existingRole = await context.env.DB.prepare(
      'SELECT id, name, description, is_active, created_at, updated_at FROM roles WHERE id = ? LIMIT 1',
    ).bind(roleId).first<RoleRow>()

    if (!existingRole) {
      return json({ success: false, error: 'Role not found' }, 404)
    }

    const nextName = typeof body.name === 'string'
      ? body.name.trim().toUpperCase()
      : existingRole.name
    const nextDescription = typeof body.description === 'string'
      ? body.description.trim()
      : existingRole.description ?? ''
    const nextIsActive = typeof body.isActive === 'boolean'
      ? (body.isActive ? 1 : 0)
      : existingRole.is_active

    if (!ROLE_NAME_PATTERN.test(nextName)) {
      return json({
        success: false,
        error: 'Role name must use uppercase letters, numbers or underscore and be at least 2 characters',
      }, 400)
    }

    if (nextDescription.length > 300) {
      return json({ success: false, error: 'Role description must be 300 characters or fewer' }, 400)
    }

    if (existingRole.name === 'SUPERADMIN' && nextName !== 'SUPERADMIN') {
      return json({ success: false, error: 'SUPERADMIN role cannot be renamed' }, 400)
    }

    if (existingRole.name === 'SUPERADMIN' && nextIsActive !== 1) {
      return json({ success: false, error: 'SUPERADMIN role cannot be deactivated' }, 400)
    }

    const updatedRole = await context.env.DB.prepare(
      `UPDATE roles
      SET name = ?, description = ?, is_active = ?, updated_at = CURRENT_TIMESTAMP
      WHERE id = ?
      RETURNING id, name, description, is_active, created_at, updated_at`,
    ).bind(nextName, nextDescription, nextIsActive, roleId).first<RoleRow>()

    if (!updatedRole) {
      throw new Error('Role update did not return a record')
    }

    return json({ success: true, role: mapRole(updatedRole) }, 200)
  } catch {
    console.error('[admin-role-update] Unable to update role')
    return json({ success: false, error: 'Unable to update role' }, 500)
  }
}
